class MyCalendarThree {
    Map<Integer, Integer> events;
    int maxK = 0;

    public MyCalendarThree() {
        events = new HashMap<>();
    }

    public int book(int startTime, int endTime) {
        int[] intervals = getIntervals(startTime, endTime);
        int k = findMaxK(intervals);
        return k;
    }

    private int[] getIntervals(int startTime, int endTime) {
        int[] intervals = new int[2];
        intervals[0] = startTime;
        intervals[1] = endTime;
        return intervals;
    }

    private int findMaxK(int[] intervals) {
        int k = 0;
        for (int interval : intervals) {
            int[] temp = new int[2];
            temp[0] = Math.min(interval, intervals[0]);
            temp[1] = Math.max(interval, intervals[1]);
            if (events.containsKey(temp[0]) && events.containsKey(temp[1])) {
                int maxK = Integer.MIN_VALUE;
                for (int i = 0; i < intervals.length; i++) {
                    if (events.containsKey(intervals[i][0]) && events.containsKey(intervals[i][1]) {
                        maxK = Math.max(maxK, intervals[i][1]);
                    }
                }
            }
        }
        return maxK;
    }
}
